import * as ed25519 from '@noble/ed25519'

import { normalizePrivateKey } from './internal'

/**
 * Sign a hash using ed25519
 * @param hash - 32 bytes long
 * @param privateKey - private key in hex format
 * @returns
 */
export async function signHash(hash: Uint8Array, privateKey: string | Uint8Array | bigint): Promise<Uint8Array> {
    if (hash.length !== 32) {
        throw new Error('Hash must be 32 bytes long')
    }

    privateKey = normalizePrivateKey(privateKey)
    const pubKey = await ed25519.getPublicKey(privateKey)
    const signature = await ed25519.sign(hash, privateKey)
    const isValid = await ed25519.verify(signature, hash, pubKey)
    if (!isValid) {
        throw new Error('Invalid signature')
    }

    return signature
}

export async function getPublicKey(privateKey: string | Uint8Array | bigint): Promise<Uint8Array> {
    privateKey = normalizePrivateKey(privateKey)
    return ed25519.getPublicKey(privateKey)
}
