import { blake2b as _blake2b } from '@noble/hashes/blake2b'
import { sha256 as _sha256 } from '@noble/hashes/sha256'
import { sha3_256 as _sha3_256 } from '@noble/hashes/sha3'

export function keccak_256(message: Uint8Array | string): Uint8Array {
    return keccak_256(message)
}

export function blake2b(message: Uint8Array | string): Uint8Array {
    return _blake2b(message)
}

export function sha3_256(message: Uint8Array | string): Uint8Array {
    return _sha3_256(message)
}

export function sha2_256(message: Uint8Array | string): Uint8Array {
    return _sha256(message)
}
